// // This module implements a 2-input, 1-output logic gate where the output X is the logical AND of B1 and C1 when both A1 and A2 are HIGH, and the output is the logical OR of B1 and C1 otherwise.
module top_module(
    input  A1,
    input  A2,
    input  B1,
    input  C1,
    output X
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign X = (A1 & A2) ? (B1 | C1) : (A1 ? C1 : (A2 ? B1 : 0));

endmodule
